const TIER_LEVELS: Record<string, number> = {
  free: 1,
  prana_flow: 2,
  siddha_quantum: 3,
  akasha_infinity: 4,
};

export function getTierLevel(tier: string | null): number {
  if (!tier) return 1;
  return TIER_LEVELS[tier] ?? 1;
}

export function canAccessLesson(userTier: string | null, lessonTier: string): boolean {
  return getTierLevel(userTier) >= getTierLevel(lessonTier);
}

export function getTierColor(tier: string): string {
  const colors: Record<string, string> = {
    free: "#D4AF37",
    prana_flow: "#22D3EE",
    siddha_quantum: "#A855F7",
    akasha_infinity: "#F59E0B",
  };
  return colors[tier] ?? "#D4AF37";
}

